import{_ as n,c as s,o as e,a0 as l}from"./chunks/framework.Bga1nt3p.js";const u=JSON.parse('{"title":"报错分析","description":"","frontmatter":{},"headers":[],"relativePath":"server-maintenance/error-analysis.md","filePath":"server-maintenance/error-analysis.md"}'),t={name:"server-maintenance/error-analysis.md"};function o(r,a,p,c,i,d){return e(),s("div",null,a[0]||(a[0]=[l(`<h1 id="报错分析" tabindex="-1">报错分析 <a class="header-anchor" href="#报错分析" aria-label="Permalink to &quot;报错分析&quot;">​</a></h1><p>相信你总是在服务器里看到眼花缭乱的黄色和红色的信息, 但你却不知道从何入手? 这时, 就需要一些基本的报错分析知识了</p><h2 id="分类" tabindex="-1">分类 <a class="header-anchor" href="#分类" aria-label="Permalink to &quot;分类&quot;">​</a></h2><p>报错一般分两种, 分别为 <code>WARN</code> (即 <code>warning</code>, 警告, 一般显示为黄色), <code>ERROR</code> (即 <code>error</code>, 错误, 一般显示为红色)</p><h2 id="普通报错" tabindex="-1">普通报错 <a class="header-anchor" href="#普通报错" aria-label="Permalink to &quot;普通报错&quot;">​</a></h2><p>先来看一些常见的报错:</p><div class="language-log line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">log</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:07</span><span style="color:#F07178;"> WARN</span><span style="color:#BABED8;">]: **** SERVER IS RUNNING IN OFFLINE/INSECURE MODE!</span></span>
<span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:07</span><span style="color:#F07178;"> WARN</span><span style="color:#BABED8;">]: The server will make no attempt to authenticate usernames. Beware.</span></span>
<span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:07</span><span style="color:#F07178;"> WARN</span><span style="color:#BABED8;">]: While this makes the game possible to play without internet access, it also opens up the ability for hackers to connect with any username they choose.</span></span>
<span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:07</span><span style="color:#F07178;"> WARN</span><span style="color:#BABED8;">]: To change this, set </span><span style="color:#C3E88D;">&quot;online-mode&quot;</span><span style="color:#BABED8;"> to </span><span style="color:#C3E88D;">&quot;true&quot;</span><span style="color:#BABED8;"> in the </span><span style="color:#89DDFF;">server.properties</span><span style="color:#BABED8;"> file.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><br><div class="language-log line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">log</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:10</span><span style="color:#C3E88D;"> ERROR</span><span style="color:#BABED8;">]: [TrMenu] SLF4J: No SLF4J providers were found.</span></span>
<span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:10</span><span style="color:#C3E88D;"> ERROR</span><span style="color:#BABED8;">]: [TrMenu] SLF4J: Defaulting to no-operation (NOP) logger implementation</span></span>
<span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:10</span><span style="color:#C3E88D;"> ERROR</span><span style="color:#BABED8;">]: [TrMenu] SLF4J: See </span><span style="color:#89DDFF;">https://www.slf4j.org/codes.html#noProviders</span><span style="color:#BABED8;"> for further details.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><br><div class="language-log line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">log</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:10</span><span style="color:#F07178;"> WARN</span><span style="color:#BABED8;">]: [ExcellentCrates] *************************</span></span>
<span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:10</span><span style="color:#F07178;"> WARN</span><span style="color:#BABED8;">]: [ExcellentCrates] You have no packet library plugins installed for the Holograms feature to work.</span></span>
<span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:10</span><span style="color:#F07178;"> WARN</span><span style="color:#BABED8;">]: [ExcellentCrates] Please install one of the following plugins to enable crate holograms: packetevents or ProtocolLib</span></span>
<span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">18:43:10</span><span style="color:#F07178;"> WARN</span><span style="color:#BABED8;">]: [ExcellentCrates] *************************</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>类似这一类直接给出消息的报错, 可以直接拿消息去翻译, 如第一个报错是对于离线服务器的警告, 第二个报错提醒没有找到 SLF4J 日志实现, 第三个报错提醒没有安装支持 Holograms 所需的 packet (包) 插件</p><div class="tip custom-block"><p class="custom-block-title">提示</p><p><em>一般</em>这一类报错不需要理会, 对游戏影响并不大</p></div><h2 id="代码报错" tabindex="-1">代码报错 <a class="header-anchor" href="#代码报错" aria-label="Permalink to &quot;代码报错&quot;">​</a></h2><p>一般的代码报错会有如下结构:</p><div class="language-log line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">log</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#BABED8;">[</span><span style="color:#676E95;font-style:italic;">14:37:31</span><span style="color:#BABED8;">] [Server thread/</span><span style="color:#C3E88D;">ERROR</span><span style="color:#BABED8;">]: Encountered an unexpected exception</span></span>
<span class="line"><span style="color:#C3E88D;">java.lang.IllegalStateException</span><span style="color:#BABED8;">: Failed to bind to port</span></span>
<span class="line"><span style="color:#C3E88D;">	at net.minecraft.server.dedicated.DedicatedServer.initServer(DedicatedServer.java:290) ~[purpur-1.21.4.jar:1.21.4-2416-51aafbc]</span></span>
<span class="line"><span style="color:#C3E88D;">	at net.minecraft.server.MinecraftServer.runServer(MinecraftServer.java:1178) ~[purpur-1.21.4.jar:1.21.4-2416-51aafbc]</span></span>
<span class="line"><span style="color:#C3E88D;">	at net.minecraft.server.MinecraftServer.lambda$spin$2(MinecraftServer.java:313) ~[purpur-1.21.4.jar:1.21.4-2416-51aafbc]</span></span>
<span class="line"><span style="color:#C3E88D;">	at java.base/java.lang.Thread.run(Thread.java:1583) ~[?:?]</span></span>
<span class="line"><span style="color:#BABED8;">Caused by: </span><span style="color:#C3E88D;">java.net.BindException</span><span style="color:#BABED8;">: Address already in use: bind</span></span>
<span class="line"><span style="color:#C3E88D;">	at java.base/sun.nio.ch.Net.bind0(Native Method) ~[?:?]</span></span>
<span class="line"><span style="color:#C3E88D;">	at java.base/sun.nio.ch.Net.bind(Net.java:565) ~[?:?]</span></span>
<span class="line"><span style="color:#C3E88D;">	at java.base/sun.nio.ch.ServerSocketChannelImpl.netBind(ServerSocketChannelImpl.java:344) ~[?:?]</span></span>
<span class="line"><span style="color:#C3E88D;">	at java.base/sun.nio.ch.ServerSocketChannelImpl.bind(ServerSocketChannelImpl.java:301) ~[?:?]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.channel.socket.nio.NioServerSocketChannel.doBind(NioServerSocketChannel.java:141) ~[netty-transport-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.channel.AbstractChannel$AbstractUnsafe.bind(AbstractChannel.java:561) ~[netty-transport-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.channel.DefaultChannelPipeline$HeadContext.bind(DefaultChannelPipeline.java:1281) ~[netty-transport-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.channel.AbstractChannelHandlerContext.invokeBind(AbstractChannelHandlerContext.java:600) ~[netty-transport-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.channel.AbstractChannelHandlerContext.bind(AbstractChannelHandlerContext.java:579) ~[netty-transport-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.channel.DefaultChannelPipeline.bind(DefaultChannelPipeline.java:922) ~[netty-transport-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.channel.AbstractChannel.bind(AbstractChannel.java:259) ~[netty-transport-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.bootstrap.AbstractBootstrap$2.run(AbstractBootstrap.java:380) ~[netty-transport-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.util.concurrent.AbstractEventExecutor.runTask(AbstractEventExecutor.java:173) ~[netty-common-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.util.concurrent.AbstractEventExecutor.safeExecute(AbstractEventExecutor.java:166) ~[netty-common-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.util.concurrent.SingleThreadEventExecutor.runAllTasks(SingleThreadEventExecutor.java:472) ~[netty-common-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.channel.nio.NioEventLoop.run(NioEventLoop.java:569) ~[netty-transport-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.util.concurrent.SingleThreadEventExecutor$4.run(SingleThreadEventExecutor.java:997) ~[netty-common-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#C3E88D;">	at io.netty.util.internal.ThreadExecutorMap$2.run(ThreadExecutorMap.java:74) ~[netty-common-4.1.115.Final.jar:4.1.115.Final]</span></span>
<span class="line"><span style="color:#BABED8;">	... </span><span style="color:#89DDFF;">1</span><span style="color:#BABED8;"> more</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br></div></div><p>我们来剖析一下结构:</p><ul><li><code>[14:37:31] [Server thread/ERROR]: Encountered an unexpected exception</code>: 前面 <code>ERROR</code> 是报错的关键字, 冒号后是报错的提示信息 (此处意为: 出现了未预期的错误)</li><li><code>java.lang.IllegalStateException: Failed to bind to port</code>: 冒号前是报错类型 (<code>IllegalStateException</code> 即 非法状态错误), 冒号后是报错的具体信息 (此处意为: 绑定端口失败)</li><li>若干个 <code>at a.b.c.d(e.java:f) ~[g:h]</code>: 意为报错出现的位置, 其中 <code>a.b.c.d</code> 是报错的 Java 路径 (一般最后一个是方法名, 倒数第二个是类名) (此处第一个意为 <code>net.minecraft.server.dedicated</code> 包中的 <code>DedicatedServer</code> 类 中的 <code>initServer</code> 方法), <code>e</code> 是报错的具体文件名, <code>f</code> 是报错的代码行数, <code>g</code> 是报错类所在的文件, <code>h</code> 是报错类所在的依赖的版本号</li><li>若干个 <code>Caused by: java.net.BindException: Address already in use: bind</code>: <code>Caused by</code> 意为 原因是 , 冒号前是导致此报错的原因 (<code>java.net.BindException</code> 即 绑定地址错误), 冒号后是具体原因 (此处意为: 端口已被占用)</li></ul><div class="info custom-block"><p class="custom-block-title">信息</p><p>一些相关定义:</p><ul><li>类: 一个文件就是一个类, 相当于一个代码文件, 类中包含方法 (函数, 用于进行一些操作), 变量 (存储值的地方) 等成员</li><li>包: 包可以理解成一个文件夹, 用 <code>.</code> 分割代表文件夹的层级关系, 包中可以包含文件 (一般是代码文件), 也可以包含子包 (文件夹)</li><li>依赖: 指的是程序运行依赖的一类库 (library), 如 Minecraft 服务器内部依赖 <code>netty</code> 库 (用于网络通信)</li><li>堆栈: 堆栈 (stack trace) 是一种用来显示程序运行时的调用关系的一种方式, 它显示了程序运行时发生的函数调用顺序, 以及函数调用时所处的位置 (文件名, 代码行数), 这里的若干行 <code>at a.b.c.d(e.java:f) ~[g:h]</code> 就是堆栈</li></ul></div><p>对于这类报错, 可以先从最后一个报错提示信息开始翻译来了解报错产生的原因, 接着可以提取堆栈中的包名, 找出类似名称的插件, 即可分析出是哪个插件出现了错误, 如果找不到该插件则一般说明是缺少了这个插件 (前置)</p>`,20)]))}const y=n(t,[["render",o]]);export{u as __pageData,y as default};
